69	\section{Universal property and the cotangent exact sequence}
70	
71	\begin{definition}\leanok
72	[Universal derivation]
73	  \label{def:universal_derivation}
74	  \lean{AlgebraicGeometry.Scheme.universalDerivation}
75	  \uses{def:relative_kaehler_sheaf}
76	  The morphism of sheaves of abelian groups $\mathrm{d} \colon \struct{X} \to \Omega_{X/S}$, defined on each affine open $V = \Spec B$ over $\Spec A$ by the Mathlib universal derivation $\mathrm{d}_{B/A} \colon B \to \Omega_{B/A}$, is the \emph{universal derivation}. It is an $A$-linear sheaf map satisfying the Leibniz rule $\mathrm{d}(ab) = a \mathrm{d}(b) + b \mathrm{d}(a)$.
77	\end{definition}
78	
79	The cotangent exact sequence is decomposed into three named ingredients before being assembled into a single theorem.
80	
81	\begin{definition}\leanok
82	[Base-change cotangent map $\alpha$]
83	  \label{def:cotangent_alpha}
84	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqAlpha}
85	  \uses{def:relative_kaehler_sheaf}
86	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{base-change cotangent map} is the natural morphism of quasi-coherent $\struct{X}$-modules
87	  \[
88	    \alpha \colon f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S}
89	  \]
90	  whose local description on an affine chart with rings $A = \struct{S}(W)$, $A' = \struct{Y}(f(V))$, $B = \struct{X}(V)$ is the standard map $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A}$ of K\"ahler differentials, $da \otimes b \mapsto b \cdot da$.
91	\end{definition}
92	
93	\begin{definition}\leanok
94	[Relative-quotient cotangent map $\beta$]
95	  \label{def:cotangent_beta}
96	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta}
97	  \uses{def:relative_kaehler_sheaf}
98	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{relative-quotient cotangent map} is the natural surjection of quasi-coherent $\struct{X}$-modules
99	  \[
100	    \beta \colon \Omega_{X/S} \;\longrightarrow\; \Omega_{X/Y}
101	  \]
102	  whose local description on an affine chart $A \to A' \to B$ is the surjection $\Omega_{B/A} \to \Omega_{B/A'}$ that kills the $A$-linear derivations factoring through $A'$.
103	\end{definition}
104	
105	\begin{lemma}\leanok
106	[Exactness of the cotangent short complex]
107	  \label{lem:cotangent_exact_structure}
108	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeq_structure}
109	  \uses{def:cotangent_alpha, def:cotangent_beta}
110	  The composition $\beta \circ \alpha$ vanishes, the resulting short complex is exact at the middle term, and $\beta$ is an epimorphism. The three ingredients are local statements whose ring-level inputs are the exactness of the Mathlib cotangent sequence $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$, together with the surjectivity of the right-hand map.
111	\end{lemma}
112	
113	\begin{proof}
114	  \uses{def:cotangent_alpha, def:cotangent_beta, lem:sheafOfModules_epi_of_epi_presheaf, lem:sheafOfModules_exact_iff_stalkwise, lem:derivation_postcomp_comp, lem:cotangent_exact_seq_beta_hη}
115	  \leanok
116	  We dispose of the three claims separately.
117	
118	  \emph{Vanishing $\beta \circ \alpha = 0$.} Inject through the adjunction
119	  $\mathrm{pullback}\,f \dashv \mathrm{pushforward}\,f$, naturality of which converts the equation into one in $Y.\mathrm{Modules}$ of the form $(\hom_{\mathrm{Adj}}\alpha) \cdot (\mathrm{pushforward}\,f).\mathrm{map}\,\beta = 0$. The left-hand side unfolds via the universal property of $\mathrm{relativeDifferentials}'\,\phi$ to a Derivation-valued equality; testing against the canonical derivation $\delta_{\phi}$ reduces the equation pointwise to ``the derivation $\delta_{\phi_2'}$ vanishes on the image of the morphism of presheaves $\phi_2$'', which is the defining property of $\delta_{\phi_2'}$. The composed-adjunction coherence required for the unfolding is the equality $\phi_g' \cdot f^c = \mathrm{unit}\,\phi_{fg}'$ (which is \texttt{rfl} at the Scheme level via $(f \cdot g).c = g.c \cdot \mathrm{pushforward}(g).\mathrm{map}\,f.c$).
120	
121	  \emph{Exactness at the middle.} The cleanest mathematical argument is stalkwise: exactness of a short complex of sheaves of modules is detected on stalks, and on each stalk one is reduced to the ring-level exactness $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$ provided by Mathlib's \texttt{KaehlerDifferential.exact\_mapBaseChange\_map}. % NOTE (iter-086+iter-087): Both routes for the Lean formalisation are confirmed infrastructurally blocked. (a) The stalkwise route requires \texttt{SheafOfModules.stalkFunctor} and a corresponding exactness-reflection theorem at the module-stalk level, neither of which exists in Mathlib (only \texttt{TopCat.Presheaf.stalkFunctor} at the AddCommGrp level is available). (b) The alternative section-wise route through \texttt{ShortComplex.exact\_map\_iff\_of\_faithful} against the faithful functor $\mathrm{SheafOfModules}\to\mathrm{PresheafOfModules}$ requires building the \texttt{PreservesLeftHomologyOf}/\texttt{PreservesRightHomologyOf} instances for that functor (also absent). The iter-085 attempt at a thin Lean shortcut via a universally-false helper signature was reverted in iter-086. \textbf{This sub-claim is deferred upstream parallel to \texttt{instIsMonoidal\_W}} (which also depends on absent Mathlib infrastructure: \texttt{stalk\_tensorObj} for varying-ring $R_0$); \texttt{case h\_exact} of \texttt{cotangentExactSeq\_structure} remains an open \texttt{sorry} pending upstream Mathlib developments.
122	
123	  \emph{Surjectivity of $\beta$.} Epimorphism is reflected through the faithful forgetful functor $\mathrm{SheafOfModules} \to \mathrm{PresheafOfModules}$: it suffices to show $\beta.\mathrm{val}$ is an epi of presheaves. The latter follows from \texttt{PresheafOfModules.epi\_iff\_surjective} together with the fact that the descent's range contains every generator $d_{\phi_2'} b$ for $b \in \Gamma(X, U)$. Indeed, by the universal property's $\texttt{Universal.fac}$ identity, the descent sends $d_{\phi_{fg}'} b \mapsto d_{\phi_2'} b$, so $d_{\phi_2'} b$ is in the range. By Mathlib's \texttt{KaehlerDifferential.span\_range\_derivation} the span of all $d b$ equals the whole module, so the range equals $\top$, hence the descent is surjective. This argument sidesteps any explicit identification of the bundled descent with \texttt{KaehlerDifferential.map}: it works directly on generators via the universal-property collapse. The reflection step is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_epi_of_epi_presheaf} below).
124	\end{proof}
125	
126	% NOTE (iter-086+iter-087): the stalkwise criterion is the cleanest mathematical statement for
127	% the cotangent-exactness argument, but its Lean formalisation requires `SheafOfModules.stalkFunctor`
128	% which is absent from Mathlib. The iter-086 alternative route (section-wise exactness + sheafification
129	% preserves exactness, via `ShortComplex.exact_map_iff_of_faithful`) is also blocked: the required
130	% `PreservesLeftHomologyOf`/`PreservesRightHomologyOf` instances for `SheafOfModules.toPresheaf` are
131	% absent from Mathlib. Both routes are deferred upstream. The `\lean{...}` hint is intentionally
132	% omitted: no Lean object corresponds to this lemma after the iter-085 false-helper revert.
133	\begin{lemma}[Stalkwise detection of exactness for sheaves of modules — mathematical statement only; not formalised]
134	  \label{lem:sheafOfModules_exact_iff_stalkwise}
135	  A short complex of sheaves of $\mathcal R$-modules is exact iff its image under each stalk functor $(-)_x$ is exact in the corresponding category of modules at $x$. This transfers an exactness statement on the sheaf side to a pointwise statement on the ring-of-stalks side, where Mathlib's $\mathrm{KaehlerDifferential}$ exactness becomes directly applicable. \emph{Deferred parallel to \texttt{instIsMonoidal\_W}} — pending an upstream Mathlib formulation of \texttt{SheafOfModules.stalkFunctor} and its exactness-reflection theorem, or of the homology-preservation instances required by the alternative section-wise+sheafification route.
136	\end{lemma}
137	
138	\begin{lemma}[Epimorphism reflection from presheaves to sheaves of modules]
139	  \label{lem:sheafOfModules_epi_of_epi_presheaf}
140	  \lean{SheafOfModules.epi_of_epi_presheaf}
141	  If $f : F \to G$ is a morphism of sheaves of $\mathcal R$-modules whose underlying morphism of presheaves $f.\mathrm{val}$ is an epi, then $f$ itself is an epi. This is immediate from the faithfulness of the forgetful functor $\mathrm{SheafOfModules}\,\mathcal R \to \mathrm{PresheafOfModules}\,\mathcal R.\mathrm{val}$ combined with the general fact that faithful functors reflect epimorphisms.
142	\end{lemma}
143	
144	\begin{lemma}[Postcomposition of a derivation distributes over composition]
145	  \label{lem:derivation_postcomp_comp}
146	  \lean{PresheafOfModules.Derivation.postcomp_comp}
147	  Let $d : R \to M$ be a derivation of presheaves of $\mathcal R$-modules and let $f : M \to N$, $g : N \to P$ be morphisms of presheaves of $\mathcal R$-modules. Then
148	  \[
149	    d.\mathrm{postcomp}(f \circ g) \;=\; (d.\mathrm{postcomp}\,f).\mathrm{postcomp}\,g.
150	  \]
151	  The proof is by Derivation extensionality on each open: both sides evaluate to $g.\mathrm{app}_U \circ f.\mathrm{app}_U \circ d_U$ at section $b$. This is a Mathlib-shape lemma about $\mathrm{Derivation}'$ that is missing from Mathlib's $\mathrm{PresheafOfModules}/\mathrm{Differentials}/\mathrm{Presheaf.lean}$.
152	\end{lemma}
153	
154	\begin{lemma}\leanok
155	[Coherence square underlying the cotangent quotient $\beta$]
156	  \label{lem:cotangent_exact_seq_beta_hη}
157	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta_hη}
158	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is a natural transformation
159	  \[
160	    \eta \colon (g \circ f)^{-1}\struct{S} \;\longrightarrow\; f_{*}(g^{-1}\struct{S})
161	  \]
162	  between sheaves of rings on $X$, satisfying the section-level coherence $\eta \circ \phi_{2}'^{\flat} = \phi_{fg}'^{\flat}$ where $\phi_{2}'^{\flat}$ and $\phi_{fg}'^{\flat}$ are the adjoint transposes of $f^{c}$ and $(g \circ f)^{c}$ respectively. This coherence is what packages the natural map $g \circ f \to g \circ f$ on rings into the descent map underlying $\beta$; exposing it as a top-level lemma makes the descent identification with Mathlib's $\mathrm{KaehlerDifferential.map}$ tractable.
163	\end{lemma}
164	
165	\begin{theorem}
166	
167	
168	\leanok
169	[Cotangent exact sequence for a composition]
170	  \label{thm:cotangent_exact_sequence}
171	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
172	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
173	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
174	  \[
175	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
176	      \Omega_{X/Y} \;\longrightarrow\; 0,
177	  \]
178	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
179	\end{theorem}
